USE stusys;

-- 生成100个学生数据
-- 1. 先生成100个sys_user记录

-- 2. 然后生成100个sys_student记录，关联到上面的sys_user
SELECT 
    u.id AS user_id, 
    CONCAT('2023', LPAD(@row_number:=@row_number+1, 3, '0')) AS student_id, 
    u.real_name AS name, 
    IF(@row_number % 2 = 0, '男', '女') AS gender, 
    DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 3650 + 3650) DAY) AS birth_date, 
    CONCAT('计算机科学与技术2023级', CEIL(@row_number / 25), '班') AS class_name, 
    u.phone, 
    u.email, 
    '在读' AS status, 
    DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 365) DAY) AS admission_date, 
    NOW() AS create_time, 
    NOW() AS update_time, 
    CEIL(@row_number / 50) AS college_id, 
    CEIL(@row_number / 25) AS major_id
FROM sys_user u, (SELECT @row_number:=0) r
WHERE u.user_name LIKE 'student%'
ORDER BY u.id;

-- 3. 验证生成结果
SELECT COUNT(*) FROM sys_user WHERE user_name LIKE 'student%';
SELECT COUNT(*) FROM sys_student;